def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    n = len(bins)
    avg_capacity = np.mean(bins[bins > 0]) if np.any(bins > 0) else 1
    median_capacity = np.median(bins[bins > 0]) if np.any(bins > 0) else 1
    std_capacity = np.std(bins[bins > 0]) if np.any(bins > 0) else 1
    for i in range(n):
        capacity = bins[i]
        if capacity <= 0:
            continue
        if item > capacity:
            continue
        ratio = item / capacity
        score = 0.0
        if ratio == 1.0:
            score = 0.0
        elif ratio > 0.85:
            score = (1 - ratio) ** 5 + 0.25
        elif 0.6 < ratio <= 0.85:
            score = np.exp(-ratio * 15) + 0.13
        elif 0.3 < ratio <= 0.6:
            acc = 0.0
            for k in range(1, 10):
                term = ((-1) ** (k+1)) * (ratio ** (k + 3)) / (k * 1.2)
                acc += term
            score = abs(acc) + 0.1
        else:
            acc = 0.0
            for p in range(1, 15):
                acc += ((-1) ** (p+1)) * (ratio ** (p + 2)) / (p * 2.0)
            score = abs(acc) + 0.15
        neighbors_influence = 0.0
        neighbors_weight_total = 0.0
        for offset in range(1, 8):
            neighbors = []
            if i - offset >= 0:
                neighbors.append(bins[i - offset])
            if i + offset < n:
                neighbors.append(bins[i + offset])
            for neighbor_capacity in neighbors:
                if neighbor_capacity > 0:
                    diff_ratio = abs(capacity - neighbor_capacity) / max(capacity, neighbor_capacity)
                    weight = 1 / (offset ** 2)
                    neighbors_influence += diff_ratio * weight * 0.08
                    neighbors_weight_total += weight
        if neighbors_weight_total > 0:
            neighbors_influence /= neighbors_weight_total
        variance_factor = (std_capacity + 1) / (median_capacity + 1)
        capacity_factor = (capacity ** 0.7) + (avg_capacity ** 0.5) * variance_factor
        if capacity_factor == 0:
            capacity_factor = 1
        penalty = 0
        if capacity < item * 1.05:
            penalty = ((item - capacity) ** 3) * 0.4
        elif capacity > item * 2:
            penalty = ((capacity - item * 2) ** 2) * 0.2
        if i % 2 == 0 and i % 7 != 0:
            score *= 0.9
            neighbors_influence *= 1.05
        elif i % 7 == 0:
            score *= 1.1
            neighbors_influence *= 0.9
        priority = score + neighbors_influence / capacity_factor + penalty
        if priority < 0:
            priority = 0
        priorities[i] = priority
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_finite = np.max(finite_priorities)
    for i in range(n):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_finite * 6
    return priorities
